const d = new Date();
const day = d.getDay();
const diff = day === 0 ? -6 : 1 - day;
d.setDate(d.getDate() + diff);
const weekStart = d.toISOString().split('T')[0];

return $input.all().map(item => ({
  json: { ...item.json, weekStart }
}));

const topic = $input.first().json;
const items = [];

for (const url of (topic.rssUrls || [])) {
  items.push({
    json: {
      feedUrl: url,
      feedType: 'rss',
      topicId: topic._id,
      topicName: topic.name,
      topicRecipients: topic.recipients,
      weekStart: topic.weekStart
    }
  });
}

for (const keyword of (topic.keywords || [])) {
  items.push({
    json: {
      feedUrl: `https://news.google.com/rss/search?q=${encodeURIComponent(keyword)}&hl=fr&gl=FR&ceid=FR:fr`,
      feedType: 'google_news',
      keyword,
      topicId: topic._id,
      topicName: topic.name,
      topicRecipients: topic.recipients,
      weekStart: topic.weekStart
    }
  });
}

return items;

const topic = $('Loop Over Items').first().json;
const allArticles = [];

for (const inputItem of $input.all()) {
  if (inputItem.json.error) continue;
  const xmlText = inputItem.json.data || '';
  if (!xmlText || typeof xmlText !== 'string') continue;

  const itemRegex = /<item>([\s\S]*?)<\/item>|<entry>([\s\S]*?)<\/entry>/g;
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const itemXml = match[1] || match[2];

    const getTag = (tag) => {
      const m = itemXml.match(new RegExp(`<${tag}(?:[^>]*)>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/${tag}>`));
      return m ? m[1].trim() : '';
    };

    const title = getTag('title');
    let url = getTag('link');
    if (!url) {
      const m = itemXml.match(/<link[^>]*href="([^"]+)"/);
      url = m ? m[1] : getTag('guid');
    }
    const pubDate = getTag('pubDate') || getTag('published') || getTag('updated');
    const content = (getTag('description') || getTag('summary') || '').replace(/<[^>]+>/g, '').slice(0, 500);

    if (!title || !url) continue;

    let source = '';
    try { source = new URL(url).hostname.replace('www.', ''); } catch(e) { source = 'unknown'; }

    allArticles.push({
      json: { title, url, pubDate, content, source, topicId: topic._id, topicName: topic.name, topicRecipients: topic.recipients, weekStart: topic.weekStart }
    });
  }
}

if (allArticles.length === 0) {
  throw new Error('Aucun article extrait des flux RSS — toutes les sources ont échoué ou sont vides.');
}

return allArticles;

const seen = new Set();
return $input.all().filter(item => {
  const url = item.json.url;
  if (!url || seen.has(url)) return false;
  seen.add(url);
  return true;
}).map(item => ({ json: item.json }));

const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
return $input.all().filter(item => {
  const pub = new Date(item.json.pubDate).getTime();
  return !isNaN(pub) && pub >= sevenDaysAgo;
}).map(item => ({ json: item.json }));

return $input.all()
  .sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate))
  .slice(0, 30)
  .map(item => ({ json: item.json }));

const articles = $input.all().map(i => i.json);
const topic = $('Loop Over Items').first().json;

if (articles.length === 0) {
  throw new Error(`Aucun article trouvé pour le sujet "${topic.name}" cette semaine.`);
}

const articleList = articles.map((a, i) =>
  `[${i+1}] TITRE: ${a.title}\nSOURCE: ${a.source}\nDATE: ${a.pubDate}\nURL: ${a.url}`
).join('\n\n---\n\n');

return [{
  json: {
    topicId: topic._id,
    topicName: topic.name,
    topicRecipients: topic.recipients,
    weekStart: topic.weekStart,
    articleCount: articles.length,
    articleList,
    rawArticles: articles
  }
}];

const d = $input.first().json;
const requestBody = {
  model: 'gpt-4o-mini',
  temperature: 0.3,
  max_tokens: 16000,
  messages: [
    {
      role: 'system',
      content: 'Tu es un analyste expert en veille stratégique, spécialisé dans le domaine "' + d.topicName + '". Tu dois TOUJOURS répondre avec un JSON valide, sans markdown, sans commentaire, uniquement le JSON brut.'
    },
    {
      role: 'user',
      content: 'Voici ' + d.articleCount + ' articles collectés cette semaine sur le sujet "' + d.topicName + '".\n\n' + d.articleList + '\n\nAnalyse ces articles et réponds UNIQUEMENT avec ce JSON (pas de markdown, juste le JSON brut) :\n\n{"synthesis": "Synthèse executive en 5-7 phrases sur les tendances clés de la semaine.", "articles": [{"title": "titre exact", "url": "url exacte", "source": "nom de la source", "category": "Stratégie|Innovation|Marchés|Réglementation|International|Autre", "summary": "résumé en 1 phrase"}]}\n\nRègles : inclus TOUS les articles, hors sujet = category Autre, n invente rien.'
    }
  ]
};

return [{
  json: {
    topicId: d.topicId,
    topicName: d.topicName,
    topicRecipients: d.topicRecipients,
    weekStart: d.weekStart,
    articleCount: d.articleCount,
    rawArticles: d.rawArticles,
    requestBody
  }
}];

const topic = $('Loop Over Items').first().json;
const raw = $input.first().json.choices?.[0]?.message?.content
  || $input.first().json.message?.content
  || $input.first().json.text
  || '';

let parsed;
try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`LLM_PARSE_ERROR: ${e.message} | Début: ${raw.slice(0, 300)}`);
}

if (!parsed.synthesis || !Array.isArray(parsed.articles)) {
  throw new Error(`LLM_STRUCTURE_ERROR: synthesis ou articles manquants`);
}

return [{
  json: {
    topicId: topic._id,
    topicName: topic.name,
    topicRecipients: topic.recipients,
    weekStart: topic.weekStart,
    synthesis: parsed.synthesis,
    articles: parsed.articles,
    generatedAt: Date.now()
  }
}];

const data = $('Parse LLM Output').first().json;
const weekLabel = new Date(data.weekStart).toLocaleDateString('fr-FR', {
  day: 'numeric', month: 'long', year: 'numeric'
});

const categoryOrder = ['Stratégie', 'Innovation', 'Marchés', 'Réglementation', 'International', 'Autre'];
const byCategory = {};
for (const article of data.articles) {
  const cat = article.category || 'Autre';
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(article);
}

const categoryBlocks = categoryOrder
  .filter(cat => byCategory[cat])
  .map(cat => {
    const items = byCategory[cat].map(a =>
      `<tr><td style="padding:12px;border-bottom:1px solid #f0f0f0;vertical-align:top;">
        <a href="${a.url}" style="color:#1a73e8;font-weight:600;text-decoration:none;">${a.title}</a><br>
        <span style="color:#888;font-size:12px;">${a.source}</span><br>
        <p style="margin:6px 0 0;color:#333;font-size:13px;line-height:1.5;">${a.summary}</p>
      </td></tr>`
    ).join('');
    return `<h3 style="color:#1a73e8;border-left:3px solid #1a73e8;padding-left:10px;margin-top:28px;">${cat}</h3>
      <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;">${items}</table>`;
  }).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;color:#333;">
  <div style="background:#1a73e8;color:white;padding:24px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;font-size:22px;">Veille ${data.topicName}</h1>
    <p style="margin:6px 0 0;opacity:0.85;font-size:14px;">Semaine du ${weekLabel} &middot; ${data.articles.length} articles analysés</p>
  </div>
  <div style="background:#f8f9fa;padding:20px;border-left:4px solid #1a73e8;margin:16px 0;border-radius:0 4px 4px 0;">
    <h2 style="margin:0 0 10px;font-size:16px;color:#1a73e8;">Synthèse de la semaine</h2>
    <p style="margin:0;line-height:1.7;">${data.synthesis}</p>
  </div>
  <h2 style="font-size:16px;margin-top:24px;">Articles par catégorie</h2>
  ${categoryBlocks}
  <div style="margin-top:32px;padding-top:16px;border-top:1px solid #eee;color:#aaa;font-size:11px;">
    Généré automatiquement le ${new Date(data.generatedAt).toLocaleString('fr-FR')} &middot; Veille Automatisée
  </div>
</body></html>`;

return [{
  json: {
    ...data,
    htmlEmail: html,
    subject: `[Veille ${data.topicName}] Semaine du ${weekLabel} — ${data.articles.length} articles`,
    to: ['developer@reboot-conseil.com']
  }
}];

const err = $input.first().json;
let topicName = 'inconnu';
try { topicName = $('Loop Over Items').first().json.name; } catch(e) {}

return [{
  json: {
    subject: `[ERREUR Veille] Sujet "${topicName}" — ${new Date().toLocaleString('fr-FR')}`,
    to: ['developer@reboot-conseil.com'],
    htmlEmail: `<p>Une erreur est survenue dans le workflow de veille pour le sujet <strong>${topicName}</strong>.</p><p><strong>Erreur :</strong> ${err.message || JSON.stringify(err)}</p><p>L'exécution continue pour les autres sujets.</p>`
  }
}];
